#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 1000
#define MAX_DIST 1000000000
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int x = 0, y = 0;
        int painted[2000][2000] = {{0}};
        painted[1000][1000] = 1;
        for (int i = 0; i < N; i++) {
            char dir;
            int dist;
            scanf(" %c %d", &dir, &dist);
            int dx = 0, dy = 0;
            if (dir == 'U') dy = 1;
            else if (dir == 'D') dy = -1;
            else if (dir == 'R') dx = 1;
            else if (dir == 'L') dx = -1;
            int count = 0;
            for (int j = 0; j < dist; j++) {
                x += dx;
                y += dy;
                if (!painted[x + 1000][y + 1000]) {
                    painted[x + 1000][y + 1000] = 1;
                    count++;
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

