import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int x = 0, y = 0;
            boolean[][] painted = new boolean[2000][2000];
            painted[1000][1000] = true;
            for (int i = 0; i < N; i++) {
                char dir = sc.next().charAt(0);
                int dist = sc.nextInt();
                int dx = 0, dy = 0;
                if (dir == 'U') dy = 1;
                else if (dir == 'D') dy = -1;
                else if (dir == 'R') dx = 1;
                else if (dir == 'L') dx = -1;
                int count = 0;
                for (int j = 0; j < dist; j++) {
                    x += dx;
                    y += dy;
                    if (!painted[x + 1000][y + 1000]) {
                        painted[x + 1000][y + 1000] = true;
                        count++;
                    }
                }
                System.out.println(count);
            }
        }
    }
}

